 1	import * as React from 'react';
 2	import {
 3	  FormGroup,
 4	  FormHelperText,
 5	  HelperText,
 6	  HelperTextItem,
 7	} from '@patternfly/react-core';
 8	import { useField } from 'formik';
 9	import { FieldProps } from '../pipelines-details/multi-column-field/types';
10	import { getFieldId } from '../pipelines-details/multi-column-field/utils';
11	import { RedExclamationCircleIcon } from '@openshift-console/dynamic-plugin-sdk';
12	
13	export interface CheckboxFieldProps extends FieldProps {
14	  formLabel?: string;
15	  value?: string;
16	  onChange?: (val: boolean) => void;
17	}
18	
19	type ToggleableFieldBaseProps = CheckboxFieldProps & {
20	  children: (props) => React.ReactNode;
21	};
22	
23	const ToggleableFieldBase: React.FC<ToggleableFieldBaseProps> = ({
24	  label,
25	  formLabel,
26	  helpText,
27	  required,
28	  children,
29	  value,
30	  onChange,
31	  name,
32	  ...props
33	}) => {
34	  const [field, { touched, error }] = useField({
35	    value,
36	    name,
37	    type: 'checkbox',
38	  });
39	  const fieldId = getFieldId(name, 'checkbox');
40	  const isValid = !(touched && error);
41	  const errorMessage = !isValid ? error : '';
42	
43	  return (
44	    <FormGroup fieldId={fieldId} label={formLabel} isRequired={required}>
45	      {children({
46	        ...field,
47	        ...props,
48	        value: field.value ?? false,
49	        id: fieldId,
50	        label,
51	        isChecked: field.checked,
52	        isValid,
53	        'aria-describedby': helpText ? `${fieldId}-helper` : undefined,
54	        onChange: (event, val) => {
55	          field.onChange(event);
56	          onChange && onChange(val);
57	        },
58	      })}
59	
60	      <FormHelperText>
61	        <HelperText>
62	          {!isValid ? (
63	            <HelperTextItem variant="error" icon={<RedExclamationCircleIcon />}>
64	              {errorMessage}
65	            </HelperTextItem>
66	          ) : (
67	            <HelperTextItem>{helpText}</HelperTextItem>
68	          )}
69	        </HelperText>
70	      </FormHelperText>
71	    </FormGroup>
72	  );
73	};
74	
75	export default ToggleableFieldBase;

